const fastify = require('fastify')({ logger: true });
const crypto = require('crypto');
const fastifyRawBody = require('fastify-raw-body');

// Register the raw body plugin to get the raw payload for signature verification
fastify.register(fastifyRawBody, {
  field: 'rawBody',
  encoding: 'utf8',
  runFirst: true,
});

// Get the API key from environment variable
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

if (!PREMBLY_API_KEY) {
  console.warn('WARNING: PREMBLY_API_KEY environment variable is not set. Signature verification will fail.');
}

/**
 * Verify the HMAC-SHA256 signature from Prembly
 * @param {string} payload - The raw request payload
 * @param {string} signature - The signature from x-prembly-signature header
 * @param {string} secret - The PREMBLY_API_KEY
 * @returns {boolean} - True if signature is valid
 */
function verifySignature(payload, signature, secret) {
  if (!signature || !secret) {
    return false;
  }

  try {
    // Compute HMAC-SHA256 of the raw payload
    const hmac = crypto.createHmac('sha256', secret);
    hmac.update(payload, 'utf8');
    const computedSignature = hmac.digest('base64');

    // Compare computed signature with received signature using timing-safe comparison
    return crypto.timingSafeEqual(
      Buffer.from(computedSignature, 'utf8'),
      Buffer.from(signature, 'utf8')
    );
  } catch (error) {
    fastify.log.error('Signature verification error:', error);
    return false;
  }
}

// Webhook endpoint
fastify.post('/webhook', async (request, reply) => {
  // Get the signature from the header
  const signature = request.headers['x-prembly-signature'];

  // Get the raw payload
  const rawPayload = request.rawBody;

  // Verify the signature
  if (!verifySignature(rawPayload, signature, PREMBLY_API_KEY)) {
    fastify.log.warn('Invalid webhook signature received');
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  // Signature is valid, process the webhook
  fastify.log.info('Webhook received and verified successfully');

  // Parse the JSON payload for processing (optional)
  try {
    const payload = JSON.parse(rawPayload);
    fastify.log.debug('Webhook payload:', payload);
    // You can add your custom webhook processing logic here
  } catch (error) {
    fastify.log.error('Failed to parse webhook payload:', error);
  }

  // Return success response
  return reply.status(200).send({ status: 'received' });
});

// Start the server
const start = async () => {
  try {
    const port = 3000;
    await fastify.listen({ port, host: '0.0.0.0' });
    fastify.log.info(`Server listening on port ${port}`);
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};

start();

